/**
 * Build a diagnostic Error from a failed `Response`.
 *
 * Replaces the old "label: <statusText>" error pattern: `statusText` is
 * empty over HTTP/2 (the prod transport), so it carried no information. This
 * helper surfaces the status code plus the server's error body — the server
 * returns `{ error }` JSON on 4xx/5xx (see `response-helpers.ts`). Fail loud,
 * with something readable in the log. See design log #203.
 *
 * Pure (no DOM/`window`), so it is importable from the service worker too.
 * It never throws: an unreadable body degrades to just the label + status, so
 * minimal `fetch` stubs in tests stay legible rather than masking the real
 * error with a TypeError from the error-builder itself.
 */
export async function apiError(response: Response, label: string): Promise<Error> {
    const detail = await readBodyDetail(response);
    const status = typeof response.status === 'number' ? String(response.status) : '';
    return new Error([`${label}:`, status, detail].filter(Boolean).join(' '));
}

async function readBodyDetail(response: Response): Promise<string> {
    let text: string;
    try {
        text = await response.text();
    } catch {
        return '';
    }
    if (!text) return '';
    try {
        const body: unknown = JSON.parse(text);
        if (body !== null && typeof body === 'object' && typeof (body as { error?: unknown }).error === 'string') {
            return (body as { error: string }).error;
        }
    } catch {
        // Not JSON — fall through to the raw text.
    }
    return text;
}
